public class CustomRecipe implements Recipe<CraftingInventory> {
    @Override
    public boolean matches(CraftingInventory inventory, World world) { return false; }
    @Override
    public ItemStack craft(CraftingInventory inventory, RegistryManager registries) { return ItemStack.EMPTY; }
    @Override
    public boolean fits(int width, int height) { return false; }
    @Override
    public ItemStack getOutput() { return ItemStack.EMPTY; }
    @Override
    public RecipeSerializer<?> getSerializer() { return null; }
    @Override
    public RecipeType<?> getType() { return null; }
}

public class CustomRecipeSerializer implements RecipeSerializer<CustomRecipe> {
    @Override
    public CustomRecipe read(Identifier id, JsonObject json) { return null; }
    @Override
    public CustomRecipe read(Identifier id, PacketByteBuf buf) { return null; }
    @Override
    public void write(PacketByteBuf buf, CustomRecipe recipe) {}
}

@Override
public ItemStack craft(CraftingInventory inventory, RegistryManager registries) {
    ItemStack result = ModItems.CUSTOM_ITEM.getDefaultStack();
    for (int i = 0; i < inventory.size(); i++) {
        ItemStack stack = inventory.getStack(i);
        if (stack.hasNbt()) {
            result.setNbt(stack.getNbt().copy());
            break;
        }
    }
    return result;
}

public class CustomRecipeDisplay implements Display {
    @Override
    public List<EntryIngredient> getInputEntries() { return null; }
    @Override
    public List<EntryIngredient> getOutputEntries() { return null; }
    @Override
    public CategoryIdentifier<?> getCategoryIdentifier() { return null; }
}
